// ── Question Engine ──────────────────────────────────────────────
// Scales to any number of questions in MYSTERY_QUESTIONS without any
// changes needed here or in the game screen.

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function byDifficulty(pool: MysteryQuestion[], difficulty: MysteryChoiceDifficulty): MysteryQuestion[] {
  return pool.filter(q => q.difficulty === difficulty)
}

/**
 * Generate exactly 10 questions for one Mystery Choice game.
 *
 * Rules:
 * - No duplicate questions within the same game.
 * - Categories and question types are randomized (shuffled pools).
 * - Difficulty follows the round progression:
 *     Rounds 1-3  → Easy and light           (difficulty 1)
 *     Rounds 4-7  → Fun and personality-based (difficulty 2)
 *     Rounds 8-10 → Deeper and meaningful     (difficulty 3)
 * - Works with any pool size (300, 500, 1000, 2000+) — just picks
 *   randomly from whichever questions exist at each difficulty.
 */
export function generateMysteryQuestions(): MysteryQuestion[] {
  const easyPool = shuffle(byDifficulty(MYSTERY_QUESTIONS, 1))
  const mediumPool = shuffle(byDifficulty(MYSTERY_QUESTIONS, 2))
  const deepPool = shuffle(byDifficulty(MYSTERY_QUESTIONS, 3))

  const EASY_COUNT = 3, MEDIUM_COUNT = 4, DEEP_COUNT = 3

  const used = new Set<string>()
  function take(pool: MysteryQuestion[], count: number): MysteryQuestion[] {
    const picked: MysteryQuestion[] = []
    for (const q of pool) {
      if (picked.length >= count) break
      if (used.has(q.id)) continue
      picked.push(q)
      used.add(q.id)
    }
    return picked
  }

  const easy = take(easyPool, EASY_COUNT)
  const medium = take(mediumPool, MEDIUM_COUNT)
  const deep = take(deepPool, DEEP_COUNT)

  // Defensive backfill: if a difficulty band ever runs short, fill remaining
  // slots from any unused question so the game always returns exactly 10.
  const target = EASY_COUNT + MEDIUM_COUNT + DEEP_COUNT
  const extra: MysteryQuestion[] = []
  if (easy.length + medium.length + deep.length < target) {
    const fallbackPool = shuffle(MYSTERY_QUESTIONS.filter(q => !used.has(q.id)))
    for (const q of fallbackPool) {
      if (easy.length + medium.length + deep.length + extra.length >= target) break
      extra.push(q)
      used.add(q.id)
    }
  }

  // Preserve the required round-by-round difficulty progression:
  // rounds 1-3 easy, 4-7 medium, 8-10 deep (each band internally shuffled).
  return [...easy, ...medium, ...deep, ...extra].slice(0, target)
}

// RoundData shape stored in game_sessions.state and rendered by the game screen.
// Keeps `en`/`gr` as 2-element arrays for binary questions (backward compatible
// with the existing premium UI), while also exposing the full option list so
// multi-select / preference questions can render up to 6 choices.
export interface RoundData {
  id: string
  category: MysteryChoiceCategory
  type: MysteryQuestionType
  question: string
  questionGr: string
  emoji: [string, string]
  en: [string, string]        // options[0]/options[1] — binary-compatible pair
  gr: [string, string]        // optionsGr[0]/optionsGr[1]
  options: string[]           // full option list (EN)
  optionsGr: string[]         // full option list (GR)
  maxSelect: number
  weight: number
  tags: string[]
}

// Convert an engine question into the RoundData shape the game screen renders.
export function toRoundData(q: MysteryQuestion): RoundData {
  const emoji = CATEGORY_EMOJI[q.category] || ['🎭', '✨']
  return {
    id: q.id,
    category: q.category,
    type: q.type,
    question: q.question,
    questionGr: q.questionGr,
    emoji,
    en: [q.options[0] || '', q.options[1] || ''],
    gr: [q.optionsGr[0] || '', q.optionsGr[1] || ''],
    options: q.options,
    optionsGr: q.optionsGr,
    maxSelect: q.maxSelect,
    weight: q.weight,
    tags: q.tags,
  }
}

// ── Weighted Compatibility Algorithm ─────────────────────────────
// Instead of only counting identical answers, this uses each question's
// weight (how much it matters) and — for multi-select questions — the
// overlap between the two players' selections, so partial agreement on
// a multi-select question still contributes partial credit.

export type RoundOutcome = 'match' | 'partial' | 'different'

export interface RoundScoreResult {
  score: number       // 0..weight
  maxScore: number     // == weight
  outcome: RoundOutcome
}

// choiceA / choiceB: a single selected option (string) for binary/single-select
// questions, or an array of selected options for multi-select questions.
export function computeRoundScore(
  round: { maxSelect: number; weight: number },
  choiceA: string | string[] | null,
  choiceB: string | string[] | null
): RoundScoreResult {
  const weight = round.weight || 1
  if (choiceA == null || choiceB == null) return { score: 0, maxScore: weight, outcome: 'different' }

  // Single-select (binary or single-pick multi/preference): exact match or not.
  if (round.maxSelect <= 1 || !Array.isArray(choiceA) || !Array.isArray(choiceB)) {
    const a = Array.isArray(choiceA) ? choiceA[0] : choiceA
    const bVal = Array.isArray(choiceB) ? choiceB[0] : choiceB
    const matched = !!a && a === bVal
    return { score: matched ? weight : 0, maxScore: weight, outcome: matched ? 'match' : 'different' }
  }

  // Multi-select: Jaccard similarity between the two selection sets,
  // scaled by the question's weight — partial overlap earns partial credit.
  const setA = new Set(choiceA)
  const setB = new Set(choiceB)
  const union = new Set([...Array.from(setA), ...Array.from(setB)])
  let intersectionCount = 0
  setA.forEach(v => { if (setB.has(v)) intersectionCount++ })
  const similarity = union.size === 0 ? 0 : intersectionCount / union.size
  const score = similarity * weight
  const outcome: RoundOutcome = similarity >= 0.66 ? 'match' : similarity > 0 ? 'partial' : 'different'
  return { score, maxScore: weight, outcome }
}

// Overall weighted compatibility percentage across a set of round results (0-100).
export function computeCompatibilityPercent(results: RoundScoreResult[]): number {
  const totalScore = results.reduce((sum, r) => sum + r.score, 0)
  const totalMax = results.reduce((sum, r) => sum + r.maxScore, 0)
  if (totalMax === 0) return 0
  return Math.round((totalScore / totalMax) * 100)
}
